operations.before_chunk_old:
// Blinn-Phong specular
vec3  H    = normalize(V + lightDir);
float spec = pow(max(dot(N, H), 0.0), specPow);

// Edge darkening
float edgeDark = pow(1.0 - normDist * 0.30, 2.0);

// Secondary internal reflection
vec3  lightDir2 = normalize(lightDir * vec3(-0.5, 0.3, 1.0));
float spec2     = pow(max(dot(N, normalize(V + lightDir2)), 0.0), specPow * 0.35) * 0.22;

vec3 sphereRGB = refractRGB * edgeDark;
sphereRGB += vec3(spec) * specMult;
sphereRGB += vec3(spec2) * 1.1;

operations.after_chunk_new:
// Edge darkening
float edgeDark = pow(1.0 - normDist * 0.30, 2.0);

vec3 sphereRGB = refractRGB * edgeDark;
// (specular highlights removed — let the motes carry the bright accents)
